import { useEffect, useState } from "react";
import api from "../services/api";

function MyRegistrationsPage() {
  const [registrations, setRegistrations] = useState([]);

  useEffect(() => {
    const fetchRegistrations = async () => {
      try {
        const storedUser = localStorage.getItem("user");

        if (!storedUser) {
          alert("Please login first");
          return;
        }

        const user = JSON.parse(storedUser);

        const response = await api.get(`/registrations/${user.id}`);
        setRegistrations(response.data);
      } catch (error) {
        console.error("Error fetching registrations:", error);
      }
    };

    fetchRegistrations();
  }, []);

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #ff9a9e, #fad0c4, #fad0c4)",
        padding: "40px 20px",
      }}
    >
      <div style={{ maxWidth: "1100px", margin: "0 auto" }}>
        <h2
          style={{
            textAlign: "center",
            color: "#333",
            fontSize: "2.5rem",
            marginBottom: "10px",
          }}
        >
          My Registrations
        </h2>

        <p
          style={{
            textAlign: "center",
            color: "#444",
            marginBottom: "30px",
          }}
        >
          Here are the events you have registered for.
        </p>

        {registrations.length === 0 ? (
          <p style={{ textAlign: "center", color: "#555" }}>
            You have not registered for any events yet.
          </p>
        ) : (
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
              gap: "25px",
            }}
          >
            {registrations.map((reg) => (
              <div
                key={reg.id}
                style={{
                  background: "white",
                  borderRadius: "20px",
                  padding: "25px",
                  boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
                }}
              >
                <h3 style={{ marginBottom: "10px" }}>
                  {reg.title || "Event"}
                </h3>

                <p style={{ marginBottom: "8px" }}>
                  <strong>Description:</strong>{" "}
                  {reg.description || "No description"}
                </p>

                <p style={{ marginBottom: "8px" }}>
                  <strong>Date:</strong> {reg.event_date}
                </p>

                <p style={{ marginBottom: "8px" }}>
                  <strong>Location:</strong> {reg.location}
                </p>

                <p style={{ marginTop: "15px", color: "#16a34a", fontWeight: "bold" }}>
                  ✔ Registered
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default MyRegistrationsPage;
